    int d_frame_no,
    int* d_endoRow,
    int* d_endoCol,
    int* d_tEndoRowLoc,
    int* d_tEndoColLoc,
    int* d_epiRow,
    int* d_epiCol,
    int* d_tEpiRowLoc,
    int* d_tEpiColLoc,
    fp* d_endoT,
    fp* d_epiT,
    fp* d_in2_all,
    fp* d_conv_all,
    fp* d_in2_pad_cumv_all,
    fp* d_in2_pad_cumv_sel_all,
    fp* d_in2_sub_cumh_all,
    fp* d_in2_sub_cumh_sel_all,
    fp* d_in2_sub2_all,
    fp* d_in2_sqr_all,
    fp* d_in2_sqr_sub2_all,
    fp* d_in_sqr_all,
    fp* d_tMask_all,
    fp* d_mask_conv_all,
    fp* d_in_mod_temp_all,
    fp* in_partial_sum_all,
    fp* in_sqr_partial_sum_all,
    fp* par_max_val_all,
    int* par_max_coo_all,
    fp* in_final_sum_all,
    fp* in_sqr_final_sum_all,
    fp* denomT_all,
    fp* checksum)
{
    int rot_row;
    int rot_col;
    int in2_rowlow;
    int in2_collow;
    int ic;
    int jc;
    int jp1;
    int ja1, ja2;
    int ip1;
    int ia1, ia2;
    int ja, jb;
    int ia, ib;
    fp s;
    int i;
    int j;
    int row;
    int col;
    int ori_row;
    int ori_col;
    int position;
    fp sum;
    int pos_ori;
    fp temp;
    fp temp2;
    int location;
    int cent;
    int tMask_row;
    int tMask_col;
    fp largest_value_current = 0;
    fp largest_value = 0;
    int largest_coordinate_current = 0;
    int largest_coordinate = 0;
    fp fin_max_val = 0;
    int fin_max_coo = 0;
    int largest_row;
    int largest_col;
    int offset_row;
    int offset_col;
    fp mean;
    fp mean_sqr;
    fp variance;
    fp deviation;
    int pointer;
    int ori_pointer;
    int loc_pointer;

