    common.in2_sub_cumh_sel2_collow = 1;
    common.in2_sub_cumh_sel2_colhig = common.in2_sub_cumh_cols - common.in_cols - 1;
    common.in2_sub2_rows = common.in2_sub_cumh_sel2_rowhig - common.in2_sub_cumh_sel2_rowlow + 1;
    common.in2_sub2_cols = common.in2_sub_cumh_sel2_colhig - common.in2_sub_cumh_sel2_collow + 1;
    common.in2_sub2_elem = common.in2_sub2_rows * common.in2_sub2_cols;
    common.in2_sub2_mem = sizeof(fp) * common.in2_sub2_elem;
    CUDA_CHECK(cudaMalloc((void**)&d_in2_sub2, common.in2_sub2_mem * common.allPoints));

    common.in2_sqr_rows = common.in2_rows;
    common.in2_sqr_cols = common.in2_cols;
    common.in2_sqr_elem = common.in2_elem;
    common.in2_sqr_mem = common.in2_mem;
    CUDA_CHECK(cudaMalloc((void**)&d_in2_sqr, common.in2_sqr_mem * common.allPoints));

    common.in2_sqr_sub2_rows = common.in2_sub2_rows;
    common.in2_sqr_sub2_cols = common.in2_sub2_cols;
    common.in2_sqr_sub2_elem = common.in2_sub2_elem;
    common.in2_sqr_sub2_mem = common.in2_sub2_mem;
    CUDA_CHECK(cudaMalloc((void**)&d_in2_sqr_sub2, common.in2_sqr_sub2_mem * common.allPoints));

    common.in_sqr_rows = common.in_rows;
    common.in_sqr_cols = common.in_cols;
    common.in_sqr_elem = common.in_elem;
    common.in_sqr_mem = common.in_mem;
    CUDA_CHECK(cudaMalloc((void**)&d_in_sqr, common.in_sqr_mem * common.allPoints));

    common.tMask_rows = common.in_rows + (common.sSize + 1 + common.sSize) - 1;
    common.tMask_cols = common.tMask_rows;
    common.tMask_elem = common.tMask_rows * common.tMask_cols;
    common.tMask_mem = sizeof(fp) * common.tMask_elem;
    CUDA_CHECK(cudaMalloc((void**)&d_tMask, common.tMask_mem * common.allPoints));

    common.mask_rows = common.maxMove;
    common.mask_cols = common.mask_rows;
    common.mask_elem = common.mask_rows * common.mask_cols;
    common.mask_mem = sizeof(fp) * common.mask_elem;

    common.mask_conv_rows = common.tMask_rows;
    common.mask_conv_cols = common.tMask_cols;
    common.mask_conv_elem = common.mask_conv_rows * common.mask_conv_cols;
    common.mask_conv_mem = sizeof(fp) * common.mask_conv_elem;
    common.mask_conv_ioffset = (common.mask_rows - 1) / 2;
    if ((common.mask_rows - 1) % 2 > 0.5) common.mask_conv_ioffset = common.mask_conv_ioffset + 1;
    common.mask_conv_joffset = (common.mask_cols - 1) / 2;
    if ((common.mask_cols - 1) % 2 > 0.5) common.mask_conv_joffset = common.mask_conv_joffset + 1;
    CUDA_CHECK(cudaMalloc((void**)&d_mask_conv, common.mask_conv_mem * common.allPoints));

    CUDA_CHECK(cudaMalloc((void**)&d_in_mod_temp, sizeof(fp) * common.in_elem * common.allPoints));
    CUDA_CHECK(cudaMalloc((void**)&d_in_partial_sum, sizeof(fp) * common.in_cols * common.allPoints));
    CUDA_CHECK(cudaMalloc((void**)&d_in_sqr_partial_sum, sizeof(fp) * common.in_sqr_rows * common.allPoints));
    CUDA_CHECK(cudaMalloc((void**)&d_par_max_val, sizeof(fp) * common.mask_conv_rows * common.allPoints));
    CUDA_CHECK(cudaMalloc((void**)&d_par_max_coo, sizeof(int) * common.mask_conv_rows * common.allPoints));
    CUDA_CHECK(cudaMalloc((void**)&d_in_final_sum, sizeof(fp) * common.allPoints));
    CUDA_CHECK(cudaMalloc((void**)&d_in_sqr_final_sum, sizeof(fp) * common.allPoints));
    CUDA_CHECK(cudaMalloc((void**)&d_denomT, sizeof(fp) * common.allPoints));
    CUDA_CHECK(cudaMalloc((void**)&d_checksum, sizeof(fp) * CHECK));

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

#ifdef TIMING
    gettimeofday(&tv_h2d_start, NULL);
#endif
    CUDA_CHECK(cudaMemcpy(d_endoRow, endoRow, common.endo_mem, cudaMemcpyHostToDevice));
    CUDA_CHECK(cudaMemcpy(d_endoCol, endoCol, common.endo_mem, cudaMemcpyHostToDevice));
    CUDA_CHECK(cudaMemcpy(d_epiRow, epiRow, common.epi_mem, cudaMemcpyHostToDevice));
    CUDA_CHECK(cudaMemcpy(d_epiCol, epiCol, common.epi_mem, cudaMemcpyHostToDevice));
#ifdef TIMING
    gettimeofday(&tv_h2d_end, NULL);
    tvsub(&tv_h2d_end, &tv_h2d_start, &tv);
    h2d_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

    dim3 block(NUMBER_THREADS, 1, 1);
    dim3 grid(common.allPoints, 1, 1);

    printf("# of workgroups = %d, # of threads/workgroup = %d (ensure that device can handle)\n",
           (int)grid.x, (int)block.x);

    printf("frame progress: ");
    fflush(NULL);

    fp* frame;
    int frame_no;

    for (frame_no = 0; frame_no < common.frames_processed; frame_no++) {
        frame = get_frame(frames, frame_no, 0, 0, 1);

#ifdef TIMING
        gettimeofday(&tv_h2d_start, NULL);
#endif
        CUDA_CHECK(cudaMemcpy(d_frame, frame, common.frame_mem, cudaMemcpyHostToDevice));
#ifdef TIMING
        gettimeofday(&tv_h2d_end, NULL);
        tvsub(&tv_h2d_end, &tv_h2d_start, &tv);
        h2d_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

#ifdef TIMING
        gettimeofday(&tv_kernel_start, NULL);
#endif
        kernel_gpu_cuda<<<grid, block>>>(
            common,
            d_frame,
            frame_no,
            d_endoRow,
            d_endoCol,
            d_tEndoRowLoc,
            d_tEndoColLoc,
            d_epiRow,
            d_epiCol,
            d_tEpiRowLoc,
            d_tEpiColLoc,
            d_endoT,
            d_epiT,
            d_in2,
            d_conv,
            d_in2_pad_cumv,
            d_in2_pad_cumv_sel,
            d_in2_sub_cumh,
            d_in2_sub_cumh_sel,
            d_in2_sub2,
            d_in2_sqr,
            d_in2_sqr_sub2,
            d_in_sqr,
            d_tMask,
            d_mask_conv,
            d_in_mod_temp,
            d_in_partial_sum,
            d_in_sqr_partial_sum,
            d_par_max_val,
            d_par_max_coo,
            d_in_final_sum,
            d_in_sqr_final_sum,
            d_denomT,
            d_checksum);
        CUDA_CHECK(cudaGetLastError());
        CUDA_CHECK(cudaDeviceSynchronize());
#ifdef TIMING
        gettimeofday(&tv_kernel_end, NULL);
        tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
        kernel_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

        free(frame);

        printf("%d ", frame_no);
        fflush(NULL);

#ifdef TEST_CHECKSUM
        fp* checksum = (fp*)malloc(sizeof(fp) * CHECK);
#ifdef TIMING
        gettimeofday(&tv_d2h_start, NULL);
#endif
        CUDA_CHECK(cudaMemcpy(checksum, d_checksum, sizeof(fp) * CHECK, cudaMemcpyDeviceToHost));
#ifdef TIMING
        gettimeofday(&tv_d2h_end, NULL);
        tvsub(&tv_d2h_end, &tv_d2h_start, &tv);
        d2h_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif
        printf("CHECKSUM:\n");
        for (i = 0; i < CHECK; i++) printf("%f ", checksum[i]);
        printf("\n\n");
        free(checksum);
#endif
    }

    printf("\n");
    fflush(NULL);

#ifdef TIMING
    gettimeofday(&tv_d2h_start, NULL);
#endif
    CUDA_CHECK(cudaMemcpy(tEndoRowLoc, d_tEndoRowLoc, common.endo_mem * common.no_frames, cudaMemcpyDeviceToHost));
    CUDA_CHECK(cudaMemcpy(tEndoColLoc, d_tEndoColLoc, common.endo_mem * common.no_frames, cudaMemcpyDeviceToHost));
    CUDA_CHECK(cudaMemcpy(tEpiRowLoc, d_tEpiRowLoc, common.epi_mem * common.no_frames, cudaMemcpyDeviceToHost));
    CUDA_CHECK(cudaMemcpy(tEpiColLoc, d_tEpiColLoc, common.epi_mem * common.no_frames, cudaMemcpyDeviceToHost));
#ifdef TIMING
    gettimeofday(&tv_d2h_end, NULL);
    tvsub(&tv_d2h_end, &tv_d2h_start, &tv);
    d2h_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

#ifdef TIMING
    gettimeofday(&tv_close_start, NULL);
#endif

    cudaFree(d_frame);
    cudaFree(d_endoRow);
    cudaFree(d_endoCol);
    cudaFree(d_tEndoRowLoc);
    cudaFree(d_tEndoColLoc);
    cudaFree(d_epiRow);
    cudaFree(d_epiCol);
    cudaFree(d_tEpiRowLoc);
    cudaFree(d_tEpiColLoc);
    cudaFree(d_endoT);
    cudaFree(d_epiT);
    cudaFree(d_in2);
    cudaFree(d_conv);
    cudaFree(d_in2_pad_cumv);
    cudaFree(d_in2_pad_cumv_sel);
    cudaFree(d_in2_sub_cumh);
    cudaFree(d_in2_sub_cumh_sel);
    cudaFree(d_in2_sub2);
    cudaFree(d_in2_sqr);
    cudaFree(d_in2_sqr_sub2);
    cudaFree(d_in_sqr);
    cudaFree(d_tMask);
    cudaFree(d_mask_conv);
    cudaFree(d_in_mod_temp);
    cudaFree(d_in_partial_sum);
    cudaFree(d_in_sqr_partial_sum);
    cudaFree(d_par_max_val);
    cudaFree(d_par_max_coo);
    cudaFree(d_in_final_sum);
    cudaFree(d_in_sqr_final_sum);
    cudaFree(d_denomT);
    cudaFree(d_checksum);

#ifdef TIMING
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
    tvsub(&tv_close_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;

    printf("Time spent in different stages of the application:\n");
    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif
}
